const SIDES: PortSide[] = ["left", "right", "top", "bottom"];

/**
 * v0.2.0 — popover triggered by the "+ add port" button. Lets the user pick
 * one or both directions via [✓in][✓out] checkboxes + type / side / multi /
 * label. On commit, calls `onAdd` with 1 or 2 atomic ports (per Q3 lock:
 * "both" creates a pair at create time; rows are independent post-save).
 *
 * Doc-typed ports have their `side` forced to `"bottom"` editor-side per Q4.
 */
export function PortEditorAddPopover({
  cardRcid,
  portTypes,
  onAdd,
  disabled,
}: {
  cardRcid: string | undefined;
  portTypes: PortType[];
  onAdd: (newPorts: Port[]) => void;
  disabled?: boolean;
}) {
  const [open, setOpen] = useState(false);
  const [inChecked, setInChecked] = useState(false);
  const [outChecked, setOutChecked] = useState(true);
  const [type, setType] = useState<string>(portTypes[0]?.id ?? "data");
  const [side, setSide] = useState<PortSide>("right");
  const [multi, setMulti] = useState(false);
  const [label, setLabel] = useState("");

  const isDocType = type === "doc";
  const effectiveSide: PortSide = isDocType ? "bottom" : side;
  const canCommit = inChecked || outChecked;

  function reset() {
    setInChecked(false);
    setOutChecked(true);
    setType(portTypes[0]?.id ?? "data");
    setSide("right");
    setMulti(false);
    setLabel("");
  }

  function commit() {
    if (!canCommit) return;
    const trimmedLabel = label.trim() === "" ? undefined : label.trim();
    let newPorts: Port[];
    if (inChecked && outChecked) {
      newPorts = makeInOutPair(
        cardRcid,
        type,
        effectiveSide,
        multi,
        trimmedLabel,
      );
    } else {
      const dir = inChecked ? "in" : "out";
      newPorts = [
        {
          id: makePortId(cardRcid),
          side: effectiveSide,
          dir,
          type,
          multi,
          label: trimmedLabel,
        },
      ];
    }
    onAdd(newPorts);
    reset();
    setOpen(false);
  }

  return (
    <Popover
      open={open}
      onOpenChange={(o) => {
        setOpen(o);
        if (!o) reset();
      }}
    >
      <PopoverTrigger asChild>
        {/* Matches rich-card's "+ FIELD" / "+ BLOCK" pattern per description Q11.
            See: rich-card/parts/predefined-add-menu.tsx:56-59 */}
        <button
          type="button"
          disabled={disabled}
          className="inline-flex items-center gap-1 rounded-md border border-dashed border-border/70 bg-transparent px-2 py-1 font-mono text-[10px] uppercase tracking-wider text-muted-foreground transition-colors hover:bg-muted hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50"
        >
          <Plus className="size-3" aria-hidden="true" />
          add port
        </button>
      </PopoverTrigger>
      <PopoverContent
        align="start"
        sideOffset={4}
        className="w-72 space-y-3 p-3"
      >
        <p className="font-mono text-[10px] uppercase tracking-wider text-muted-foreground">
          Add port
        </p>

        {/* Direction multi-select per Q3 — both checked creates an in/out pair */}
        <div className="space-y-1.5">
          <Label className="text-xs font-medium">Direction</Label>
          <div className="flex items-center gap-3">
            <label className="flex items-center gap-1.5 text-xs">
              <Checkbox
                checked={inChecked}
                onCheckedChange={(c) => setInChecked(c === true)}
              />
              in
            </label>
            <label className="flex items-center gap-1.5 text-xs">
              <Checkbox
                checked={outChecked}
                onCheckedChange={(c) => setOutChecked(c === true)}
              />
              out
            </label>
          </div>
        </div>

        <div className="space-y-1.5">
          <Label className="text-xs font-medium">Type</Label>
          <Select value={type} onValueChange={(v: string | null) => v && setType(v)}>
            <SelectTrigger className="h-8 w-full text-xs">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {portTypes.map((t) => (
                <SelectItem key={t.id} value={t.id} className="text-xs">
                  <span className="flex items-center gap-2">
                    <span
                      className="inline-block size-2.5 rounded-full"
                      style={{ background: t.color }}
                      aria-hidden="true"
                    />
                    {t.label ?? t.id}
                  </span>
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        <div className="space-y-1.5">
          <Label className="text-xs font-medium">Side</Label>
          <Select
            value={effectiveSide}
            onValueChange={(v: string | null) => v && setSide(v as PortSide)}
            disabled={isDocType}
          >
            <SelectTrigger className="h-8 w-full text-xs">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {SIDES.map((s) => (
                <SelectItem
                  key={s}
                  value={s}
                  className="text-xs"
                  disabled={isDocType && s !== "bottom"}
                >
                  {s}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          {isDocType && (
            <p className="text-[10px] text-muted-foreground">
              Doc-type ports are forced to the bottom side.
            </p>
          )}
        </div>

        <label className="flex items-center gap-2">
          <Checkbox
            checked={multi}
            onCheckedChange={(c) => setMulti(c === true)}
          />
          <span className="text-xs">Allow multiple connections</span>
        </label>

        <div className="space-y-1.5">
          <Label htmlFor="rcif-port-add-label" className="text-xs font-medium">
            Label (optional)
          </Label>
          <Input
            id="rcif-port-add-label"
            value={label}
            onChange={(e) => setLabel(e.target.value)}
            placeholder="e.g. response, doc-ref"
            className="h-8 text-xs"
          />
        </div>

        <div className="flex items-center justify-end gap-2 pt-1">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => {
              reset();
              setOpen(false);
            }}
          >
            Cancel
          </Button>
          <Button size="sm" onClick={commit} disabled={!canCommit}>
            Add
          </Button>
        </div>
      </PopoverContent>
    </Popover>
  );
}

"use client";

import { memo, useState } from "react";
import { AlertCircle, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";
// F-S1 lock — RELATIVE cross-procomp imports
import type {
  Port,
  PortDir,
  PortSide,
  PortType,
} from "../../flow-canvas-01/types";
import { isDuplicateId } from "../lib/port-mutators";
import type { PortEditorPermissions, PortField } from "../types";

const SIDES: PortSide[] = ["left", "right", "top", "bottom"];
const DIRS: PortDir[] = ["in", "out"];

export type PortEditorRowProps = {
  cardId: string;
  port: Port;
  portTypes: PortType[];
  existingPorts: Port[];
  liveEdgeCount: { asSource: number; asTarget: number };
  editable: boolean;
  permissions: PortEditorPermissions;
  onUpdate: (mut: Partial<Port>) => void;
  onRemove: () => void;
};

function PortEditorRowImpl({
  cardId,
  port,
  portTypes,
  existingPorts,
  liveEdgeCount,
  editable,
  permissions,
  onUpdate,
  onRemove,
}: PortEditorRowProps) {
  // Local buffers for commit-on-blur text fields (id, label). Live-save for
  // selects + checkbox per Q6/Q7 — id renames have edge implications so they
  // commit on blur; label is no-op for runtime but still uses blur for consistency.
  //
  // Note: the parent strip uses key={port.id} so id-rename commits remount the
  // row (drafts reset cleanly from the new port props). External label-only
  // mutations mid-edit don't re-sync the draft (edge case; v0.3 fix if a
  // consumer hits it). Avoids the React Compiler "setState during effect"
  // cascading-renders warning.
  const [idDraft, setIdDraft] = useState(port.id);
  const [labelDraft, setLabelDraft] = useState(port.label ?? "");

  const isDocType = port.type === "doc";
  const totalLiveEdges = liveEdgeCount.asSource + liveEdgeCount.asTarget;
  const hasLiveEdges = totalLiveEdges > 0;
  const idIsDirty = idDraft !== port.id;

  const canEdit =
    editable && (permissions.canEditPort?.(cardId, port.id) ?? true);
  const canEditField = (field: PortField): boolean =>
    canEdit && (permissions.canEditPortField?.(cardId, port.id, field) ?? true);
  const canRemove =
    editable && (permissions.canRemovePort?.(cardId, port.id) ?? true);

  const idError =
    idDraft.trim() === ""
      ? "Port id required"
      : isDuplicateId(existingPorts, idDraft, port.id)
        ? "Port id must be unique within this node"
        : null;

  function commitId() {
    const trimmed = idDraft.trim();
    if (trimmed === "" || trimmed === port.id) {
      setIdDraft(port.id);
      return;
    }
    if (isDuplicateId(existingPorts, trimmed, port.id)) {
      setIdDraft(port.id);
      return;
    }
    onUpdate({ id: trimmed });
  }

  function commitLabel() {
    const trimmed = labelDraft.trim();
    if (trimmed === (port.label ?? "")) return;
    onUpdate({ label: trimmed === "" ? undefined : trimmed });
  }

  function handleTypeChange(v: string | null) {
    if (!v) return;
    // Q4 auto-correct: switching to "doc" forces side to "bottom".
    if (v === "doc" && port.side !== "bottom") {
      onUpdate({ type: v, side: "bottom" });
    } else {
      onUpdate({ type: v });
    }
  }

  if (!editable) {
    // F-08 read-only summary row. Mirrors the editable row's fixed-pixel
    // column widths so rows align cleanly. No remove / no multi columns.
    return (
      <div className="grid grid-cols-[220px_120px_100px_80px_200px] items-center gap-1 rounded-sm border border-border/40 bg-card/30 px-2 py-1.5 text-xs">
        <div className="truncate font-mono">{port.id}</div>
        <PortTypeBadge type={port.type} portTypes={portTypes} />
        <span className="text-muted-foreground">{port.side}</span>
        <span className="text-muted-foreground">{port.dir}</span>
        {port.label ? (
          <span className="truncate text-muted-foreground">{port.label}</span>
        ) : (
          <span />
        )}
      </div>
    );
  }

  const idField = (
    <div className="relative">
      <Input
        value={idDraft}
        onChange={(e) => setIdDraft(e.target.value)}
        onBlur={commitId}
        disabled={!canEditField("id")}
        className={`h-7 pr-6 font-mono text-xs ${idError ? "border-destructive" : ""}`}
        aria-invalid={idError !== null}
      />
      {hasLiveEdges && idIsDirty && !idError && (
        <AlertCircle
          className="pointer-events-none absolute right-1.5 top-1.5 size-3 text-warning"
          aria-label="Rename will affect existing edges"
        />
      )}
    </div>
  );

  return (
    // Fixed-pixel column widths sized for actual control content (no fr
    // stretching — at wide parents the fr-grown columns made selects look
    // unnecessarily wide). Row sits at natural width (~860px) anchored left;
    // the strip's overflow-x-auto wrapper kicks in if the parent is narrower.
    // Widths: id 220 / type 120 / side 100 / dir 80 / multi 80 / label 200 /
    // remove 36 = 836 + 6×4 gaps = 860.
    <div className="grid grid-cols-[220px_120px_100px_80px_80px_200px_36px] items-center gap-1 rounded-sm border border-border/40 bg-card/30 px-2 py-1.5">
      {/* ID — commit on blur; tooltip when error OR live-edges warning */}
      {idError ? (
        <Tooltip>
          <TooltipTrigger asChild>{idField}</TooltipTrigger>
          <TooltipContent>{idError}</TooltipContent>
        </Tooltip>
      ) : hasLiveEdges && idIsDirty ? (
        <Tooltip>
          <TooltipTrigger asChild>{idField}</TooltipTrigger>
          <TooltipContent>
            Renaming this port will not auto-update {totalLiveEdges} existing edge
            {totalLiveEdges === 1 ? "" : "s"} — consumer must update edge references.
          </TooltipContent>
        </Tooltip>
      ) : (
        idField
      )}

      {/* Type — live-save; auto-corrects side when switching to "doc" */}
      <Select
        value={port.type}
        onValueChange={handleTypeChange}
        disabled={!canEditField("type")}
      >
        <SelectTrigger className="h-7 w-full text-xs">
          <SelectValue />
        </SelectTrigger>
        <SelectContent>
          {portTypes.map((t) => (
            <SelectItem key={t.id} value={t.id} className="text-xs">
              <span className="flex items-center gap-2">
                <span
                  className="inline-block size-2.5 rounded-full"
                  style={{ background: t.color }}
                  aria-hidden="true"
                />
                {t.label ?? t.id}
              </span>
            </SelectItem>
          ))}
        </SelectContent>
      </Select>

      {/* Side — disabled for doc-type per Q4 */}
      <Select
        value={port.side}
        onValueChange={(v: string | null) => v && onUpdate({ side: v as PortSide })}
        disabled={!canEditField("side") || isDocType}
      >
        <SelectTrigger className="h-7 w-full text-xs">
          <SelectValue />
        </SelectTrigger>
        <SelectContent>
          {SIDES.map((s) => (
            <SelectItem
              key={s}
              value={s}
              className="text-xs"
              disabled={isDocType && s !== "bottom"}
            >
              {s}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>

      {/* Dir */}
      <Select
        value={port.dir}
        onValueChange={(v: string | null) => v && onUpdate({ dir: v as PortDir })}
        disabled={!canEditField("dir")}
      >
        <SelectTrigger className="h-7 w-full text-xs">
          <SelectValue />
        </SelectTrigger>
        <SelectContent>
          {DIRS.map((d) => (
            <SelectItem key={d} value={d} className="text-xs">
              {d}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>

      {/* Multi */}
      <label className="flex items-center gap-1 text-[10px] uppercase tracking-wide text-muted-foreground">
        <Checkbox
          checked={port.multi === true}
          onCheckedChange={(c) => onUpdate({ multi: c === true })}
          disabled={!canEditField("multi")}
        />
        multi
      </label>

      {/* Label — commit on blur */}
      <Input
        value={labelDraft}
        onChange={(e) => setLabelDraft(e.target.value)}
        onBlur={commitLabel}
        disabled={!canEditField("label")}
        placeholder="label"
        className="h-7 text-xs"
      />

      {/* Remove */}
      <Button
        variant="ghost"
        size="sm"
        onClick={onRemove}
        disabled={!canRemove}
        className="size-7 p-0"
        aria-label={`Remove port ${port.id}`}
      >
        <X className="size-3.5" />
      </Button>
    </div>
  );
}

function PortTypeBadge({
  type,
  portTypes,
}: {
  type: string;
  portTypes: PortType[];
}) {
  const pt = portTypes.find((t) => t.id === type);
  return (
    <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
      <span
        className="inline-block size-2.5 rounded-full"
        style={{ background: pt?.color ?? "var(--muted-foreground)" }}
        aria-hidden="true"
      />
      {pt?.label ?? type}
    </span>
  );
}

